import type { ComponentProps, ComponentRef } from 'react';
import {
  Drawer as DrawerPrimitive,
  useDrawer,
  useDrawerContext,
  useDrawerStackContext,
} from '@ark-ui/react/drawer';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { CloseButton } from '../close-button';
import styles from './Drawer.module.css';

const DEFAULT_CLOSE_BUTTON_LABEL = 'Close drawer';

function DrawerRoot({
  lazyMount = true,
  unmountOnExit = true,
  ...props
}: ComponentProps<typeof DrawerPrimitive.Root>) {
  return <DrawerPrimitive.Root lazyMount={lazyMount} unmountOnExit={unmountOnExit} {...props} />;
}

function DrawerRootProvider({
  lazyMount = true,
  unmountOnExit = true,
  ...props
}: ComponentProps<typeof DrawerPrimitive.RootProvider>) {
  return (
    <DrawerPrimitive.RootProvider lazyMount={lazyMount} unmountOnExit={unmountOnExit} {...props} />
  );
}

const DrawerStack = DrawerPrimitive.Stack;

const DrawerTrigger = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Trigger>,
  ComponentProps<typeof DrawerPrimitive.Trigger>
>(function DrawerTrigger({ asChild, className, ...props }, ref) {
  return (
    <DrawerPrimitive.Trigger
      ref={ref}
      asChild={asChild}
      data-slot="drawer-trigger"
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerBackdrop = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Backdrop>,
  ComponentProps<typeof DrawerPrimitive.Backdrop>
>(function DrawerBackdrop({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.Backdrop
      ref={ref}
      data-slot="drawer-backdrop"
      className={clsx(styles.backdrop, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerPositioner = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Positioner>,
  ComponentProps<typeof DrawerPrimitive.Positioner>
>(function DrawerPositioner({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.Positioner
      ref={ref}
      data-slot="drawer-positioner"
      className={clsx(styles.positioner, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerContent = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Content>,
  ComponentProps<typeof DrawerPrimitive.Content>
>(function DrawerContent({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.Content
      ref={ref}
      data-slot="drawer-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerGrabber = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Grabber>,
  ComponentProps<typeof DrawerPrimitive.Grabber>
>(function DrawerGrabber({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.Grabber
      ref={ref}
      data-slot="drawer-grabber"
      className={clsx(styles.grabber, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerGrabberIndicator = forwardRef<
  ComponentRef<typeof DrawerPrimitive.GrabberIndicator>,
  ComponentProps<typeof DrawerPrimitive.GrabberIndicator>
>(function DrawerGrabberIndicator({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.GrabberIndicator
      ref={ref}
      data-slot="drawer-grabber-indicator"
      className={clsx(styles.grabberIndicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerTitle = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Title>,
  ComponentProps<typeof DrawerPrimitive.Title>
>(function DrawerTitle({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.Title
      ref={ref}
      data-slot="drawer-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerDescription = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Description>,
  ComponentProps<typeof DrawerPrimitive.Description>
>(function DrawerDescription({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.Description
      ref={ref}
      data-slot="drawer-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerCloseTrigger = forwardRef<
  ComponentRef<typeof DrawerPrimitive.CloseTrigger>,
  ComponentProps<typeof DrawerPrimitive.CloseTrigger>
>(function DrawerCloseTrigger({ asChild, className, ...props }, ref) {
  return (
    <DrawerPrimitive.CloseTrigger
      ref={ref}
      asChild={asChild}
      data-slot="drawer-close-trigger"
      className={clsx(!asChild && styles.closeTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerCloseIcon = forwardRef<
  ComponentRef<typeof CloseButton.Root>,
  Omit<ComponentProps<typeof DrawerPrimitive.CloseTrigger>, 'asChild'>
>(function DrawerCloseIcon(
  { className, children, 'aria-label': ariaLabel = DEFAULT_CLOSE_BUTTON_LABEL, ...props },
  ref,
) {
  return (
    <DrawerPrimitive.CloseTrigger asChild {...props}>
      <CloseButton.Root
        ref={ref}
        data-slot="drawer-close-icon"
        aria-label={ariaLabel}
        className={clsx(styles.closeIcon, normalizeClassName(className))}
      >
        {children}
      </CloseButton.Root>
    </DrawerPrimitive.CloseTrigger>
  );
});

const DrawerSwipeArea = forwardRef<
  ComponentRef<typeof DrawerPrimitive.SwipeArea>,
  ComponentProps<typeof DrawerPrimitive.SwipeArea>
>(function DrawerSwipeArea({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.SwipeArea
      ref={ref}
      data-slot="drawer-swipe-area"
      className={clsx(styles.swipeArea, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerIndent = forwardRef<
  ComponentRef<typeof DrawerPrimitive.Indent>,
  ComponentProps<typeof DrawerPrimitive.Indent>
>(function DrawerIndent({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.Indent
      ref={ref}
      data-slot="drawer-indent"
      className={clsx(styles.indent, normalizeClassName(className))}
      {...props}
    />
  );
});

const DrawerIndentBackground = forwardRef<
  ComponentRef<typeof DrawerPrimitive.IndentBackground>,
  ComponentProps<typeof DrawerPrimitive.IndentBackground>
>(function DrawerIndentBackground({ className, ...props }, ref) {
  return (
    <DrawerPrimitive.IndentBackground
      ref={ref}
      data-slot="drawer-indent-background"
      className={clsx(styles.indentBackground, normalizeClassName(className))}
      {...props}
    />
  );
});

function DrawerHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="drawer-header" className={clsx(styles.header, className)} {...props} />;
}

function DrawerBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="drawer-body" className={clsx(styles.body, className)} {...props} />;
}

function DrawerFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="drawer-footer" className={clsx(styles.footer, className)} {...props} />;
}

const DrawerContext = DrawerPrimitive.Context;

const Drawer = Object.assign(DrawerRoot, {
  Root: DrawerRoot,
  RootProvider: DrawerRootProvider,
  Stack: DrawerStack,
  Trigger: DrawerTrigger,
  Backdrop: DrawerBackdrop,
  Positioner: DrawerPositioner,
  Content: DrawerContent,
  Grabber: DrawerGrabber,
  GrabberIndicator: DrawerGrabberIndicator,
  Title: DrawerTitle,
  Description: DrawerDescription,
  CloseTrigger: DrawerCloseTrigger,
  CloseIcon: DrawerCloseIcon,
  SwipeArea: DrawerSwipeArea,
  Indent: DrawerIndent,
  IndentBackground: DrawerIndentBackground,
  Header: DrawerHeader,
  Body: DrawerBody,
  Footer: DrawerFooter,
  Context: DrawerContext,
});

export { Drawer, useDrawer, useDrawerContext, useDrawerStackContext };
export type {
  DrawerBackdropProps,
  DrawerCloseTriggerProps,
  DrawerContentProps,
  DrawerContextProps,
  DrawerDescriptionProps,
  DrawerGrabberIndicatorProps,
  DrawerGrabberProps,
  DrawerIndentBackgroundProps,
  DrawerIndentProps,
  DrawerOpenChangeDetails,
  DrawerPositionerProps,
  DrawerRootProps,
  DrawerRootProviderProps,
  DrawerSnapPointChangeDetails,
  DrawerStackProps,
  DrawerSwipeAreaProps,
  DrawerTitleProps,
  DrawerTriggerProps,
  DrawerTriggerValueChangeDetails,
  UseDrawerContext,
  UseDrawerProps,
  UseDrawerReturn,
  UseDrawerStackContext,
} from '@ark-ui/react/drawer';

@layer ui.components {
  .trigger,
  .closeTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-height: var(--drawer-control-height, var(--size-lg));
    margin: 0;
    padding: var(--drawer-control-padding-y, 0.5rem) var(--drawer-control-padding-x, 0.875rem);
    border: var(--drawer-control-border-width, var(--border-width-sm)) solid
      var(--drawer-control-border-color, var(--color-border));
    border-radius: var(--drawer-control-radius, var(--radius-md));
    background-color: var(--drawer-control-bg, var(--color-background));
    color: var(--drawer-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--drawer-control-font-size, var(--text-md));
    line-height: var(--drawer-control-line-height, var(--line-height-text-md));
    cursor: pointer;
    user-select: none;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--drawer-control-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      outline: var(
          --drawer-focus-ring-width,
          var(--drawer-control-border-width, var(--border-width-sm))
        )
        solid var(--drawer-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(--drawer-focus-ring-width, var(--drawer-control-border-width, var(--border-width-sm))) *
          -1
      );
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--opacity-disabled);
    }
  }

  .backdrop {
    position: fixed;
    z-index: calc(var(--z-backdrop) + var(--layer-index, 0));
    inset: 0;
    min-height: 100dvh;
    background-color: var(--drawer-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--drawer-backdrop-blur, 4px)));
    opacity: calc(1 - var(--drawer-swipe-progress, 0));
    transition:
      opacity calc(var(--drawer-swipe-strength, 1) * var(--duration-slower)) var(--ease-out),
      backdrop-filter calc(var(--drawer-swipe-strength, 1) * var(--duration-slower)) var(--ease-out);

    &[data-state='open'] {
      animation: drawer-backdrop-in var(--drawer-backdrop-transition, var(--transition-spring));
    }

    &[data-state='closed'] {
      animation: drawer-backdrop-out var(--drawer-backdrop-transition, var(--transition-spring));
      animation-fill-mode: forwards;
    }

    &[data-state='open'][data-swiping] {
      transition-duration: 0s;
    }

    &[hidden]:has(~ .positioner:not([hidden])) {
      display: block;
    }
  }

  .positioner {
    box-sizing: border-box;
    position: fixed;
    z-index: calc(var(--z-modal) + var(--layer-index, 0));
    inset: 0;
    display: flex;
    align-items: flex-end;
    justify-content: center;
    overflow: hidden;
    overscroll-behavior: contain;
    padding: var(--drawer-positioner-padding, 0);

    &[data-swipe-direction='up'] {
      align-items: flex-start;
    }

    &[data-swipe-direction='left'] {
      align-items: stretch;
      justify-content: flex-start;
    }

    &[data-swipe-direction='right'] {
      align-items: stretch;
      justify-content: flex-end;
    }

    &:not([hidden]) {
      .content[hidden] {
        display: flex;
      }
    }
  }

  .content {
    --drawer-bleed: var(--drawer-bleed-size, 3rem);
    box-sizing: border-box;
    position: relative;
    display: flex;
    flex-direction: column;
    width: min(var(--drawer-width, 100%), 100vw);
    height: var(--drawer-size, 100%);
    max-height: var(--drawer-max-height, 80dvh);
    padding: var(--drawer-padding-y, var(--spacing-2)) var(--drawer-padding-x, var(--spacing-6))
      calc(var(--drawer-padding-y, var(--spacing-4)) + env(safe-area-inset-bottom, 0px));
    border: var(--drawer-border-width, var(--border-width-sm)) solid
      var(--drawer-border-color, var(--color-border));
    border-radius: var(--drawer-radius, var(--radius-xl)) var(--drawer-radius, var(--radius-xl)) 0 0;
    outline: 0;
    background-color: var(--drawer-bg, var(--color-popover));
    color: var(--drawer-color, var(--color-popover-foreground));
    box-shadow: var(--drawer-shadow, var(--shadow-lg));
    overscroll-behavior: contain;
    transition:
      transform calc(var(--drawer-swipe-strength, 1) * var(--duration-slower)) var(--ease-out),
      height calc(var(--drawer-swipe-strength, 1) * var(--duration-slower)) var(--ease-out);

    &::after {
      position: absolute;
      inset-inline: 0;
      top: 100%;
      height: var(--drawer-bleed);
      background-color: inherit;
      content: '';
      pointer-events: none;
    }

    &[data-state='open'] {
      animation: drawer-content-in-down var(--drawer-transition, var(--transition-spring));
    }

    &[data-state='closed'] {
      animation: drawer-content-out-down var(--drawer-transition, var(--transition-spring));
      animation-fill-mode: forwards;
    }

    &[data-state='open'][data-swiping],
    &[data-nested-drawer-swiping] {
      transition-duration: 0s;
    }

    &[data-dragging] {
      user-select: none;
    }

    &[data-swipe-direction='up'] {
      padding-top: calc(var(--drawer-padding-y, var(--spacing-4)) + env(safe-area-inset-top, 0px));
      padding-bottom: var(--drawer-padding-y, var(--spacing-4));
      border-radius: 0 0 var(--drawer-radius, var(--radius-xl))
        var(--drawer-radius, var(--radius-xl));

      &::after {
        top: auto;
        bottom: 100%;
      }

      &[data-state='open'] {
        animation-name: drawer-content-in-up;
      }

      &[data-state='closed'] {
        animation-name: drawer-content-out-up;
      }
    }

    &[data-swipe-direction='left'],
    &[data-swipe-direction='right'] {
      width: min(var(--drawer-side-width, 22rem), calc(100vw - var(--spacing-8)));
      height: var(--drawer-side-height, 100%);
      max-height: none;
      padding: var(--drawer-padding-y, var(--spacing-6)) var(--drawer-padding-x, var(--spacing-6));

      &::after {
        inset-block: 0;
        inset-inline: auto;
        top: 0;
        width: var(--drawer-bleed);
        height: auto;
      }
    }

    &[data-swipe-direction='left'] {
      border-radius: 0 var(--drawer-radius, var(--radius-xl)) var(--drawer-radius, var(--radius-xl))
        0;

      &::after {
        right: 100%;
      }

      &[data-state='open'] {
        animation-name: drawer-content-in-left;
      }

      &[data-state='closed'] {
        animation-name: drawer-content-out-left;
      }
    }

    &[data-swipe-direction='right'] {
      border-radius: var(--drawer-radius, var(--radius-xl)) 0 0
        var(--drawer-radius, var(--radius-xl));

      &::after {
        left: 100%;
      }

      &[data-state='open'] {
        animation-name: drawer-content-in-right;
      }

      &[data-state='closed'] {
        animation-name: drawer-content-out-right;
      }
    }

    &[data-nested-drawer-open] {
      transform-origin: center bottom;
      scale: calc(1 - var(--drawer-nested-scale-step, 0.05) * var(--nested-drawers, 0));
    }
  }

  .grabber {
    display: flex;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    width: 100%;
    padding: var(--drawer-grabber-padding, var(--spacing-3)) 0;
    cursor: grab;
    user-select: none;

    &:active {
      cursor: grabbing;
    }

    :where(.content[data-swipe-direction='left'], .content[data-swipe-direction='right']) & {
      display: none;
    }
  }

  .grabberIndicator {
    width: var(--drawer-grabber-indicator-width, 3rem);
    height: var(--drawer-grabber-indicator-height, 0.25rem);
    border-radius: var(--drawer-grabber-indicator-radius, var(--radius-full));
    background-color: var(--drawer-grabber-indicator-bg, var(--color-muted-foreground));
    opacity: var(--drawer-grabber-indicator-opacity, 0.45);
    transition:
      background-color var(--transition-default),
      opacity var(--transition-default);

    @media (hover: hover) {
      .grabber:hover & {
        opacity: var(--drawer-grabber-indicator-opacity-hover, 0.7);
      }
    }
  }

  .header {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    align-items: start;
    gap: var(--drawer-header-gap, var(--spacing-1));

    & > [data-slot='drawer-title'] {
      grid-column: 1;
    }

    & > [data-slot='drawer-close-trigger'],
    & > [data-slot='drawer-close-icon'] {
      grid-column: 2;
      justify-self: end;
    }

    & > [data-slot='drawer-description'] {
      grid-column: 1 / -1;
    }
  }

  .title {
    margin: 0;
    color: var(--drawer-title-color, var(--drawer-color, var(--color-popover-foreground)));
    font-size: var(--drawer-title-font-size, var(--text-lg));
    font-weight: var(--drawer-title-font-weight, var(--weight-semibold));
    line-height: var(--drawer-title-line-height, var(--line-height-text-lg));
  }

  .description,
  .body {
    color: var(--drawer-description-color, var(--color-muted-foreground));
    font-size: var(--drawer-description-font-size, var(--text-md));
    line-height: var(--drawer-description-line-height, var(--line-height-text-md));
  }

  .description {
    margin: 0;
  }

  .body {
    min-height: 0;
    margin-top: var(--drawer-body-margin-top, var(--spacing-4));
    overflow-y: auto;
  }

  .footer {
    display: flex;
    justify-content: flex-end;
    gap: var(--drawer-footer-gap, var(--spacing-2));
    margin-top: var(--drawer-footer-margin-top, var(--spacing-6));
  }

  .closeIcon {
    --close-button-size: var(--drawer-close-icon-size, 1.75rem);
    --close-button-radius: var(--drawer-close-icon-radius, var(--radius-md));
    --close-button-color: var(
      --drawer-close-icon-color,
      var(--drawer-description-color, var(--color-muted-foreground))
    );
    --close-button-color-hover: var(
      --drawer-close-icon-color-hover,
      var(--drawer-color, var(--color-popover-foreground))
    );
    --close-button-bg: var(--drawer-close-icon-bg, transparent);
    --close-button-bg-hover: var(--drawer-close-icon-bg-hover, var(--color-accent));
    --close-button-focus-ring-color: var(
      --drawer-close-icon-focus-ring-color,
      var(--drawer-focus-ring-color, var(--color-ring))
    );
    --close-button-icon-size: var(--drawer-close-icon-glyph-size, 0.75rem);
  }

  .swipeArea {
    position: fixed;
    z-index: var(--z-modal);
    touch-action: none;

    &[data-swipe-direction='up'] {
      right: 0;
      bottom: 0;
      left: 0;
      height: var(--drawer-swipe-area-size, var(--spacing-10));
    }

    &[data-swipe-direction='down'] {
      top: 0;
      right: 0;
      left: 0;
      height: var(--drawer-swipe-area-size, var(--spacing-10));
    }

    &[data-swipe-direction='left'] {
      top: 0;
      right: 0;
      bottom: 0;
      width: var(--drawer-swipe-area-size, var(--spacing-10));
    }

    &[data-swipe-direction='right'] {
      top: 0;
      bottom: 0;
      left: 0;
      width: var(--drawer-swipe-area-size, var(--spacing-10));
    }

    &[data-disabled] {
      pointer-events: none;
    }
  }

  .indentBackground {
    position: absolute;
    inset: 0;
    background: var(--drawer-indent-background-bg, var(--color-foreground));
    opacity: var(--drawer-indent-background-opacity, 0);
    pointer-events: none;
    transition: opacity var(--drawer-indent-transition, var(--transition-spring));

    &[data-active] {
      opacity: calc(
        var(--drawer-indent-background-opacity-active, 1) * (1 - var(--drawer-swipe-progress, 0))
      );
    }
  }

  .indent {
    position: relative;
    transform: translateY(0) scale(1);
    transform-origin: center top;
    transition:
      transform var(--drawer-indent-transition, var(--transition-spring)),
      border-radius var(--drawer-indent-transition, var(--transition-spring));

    &[data-active] {
      border-radius: var(--drawer-indent-radius-active, var(--radius-lg))
        var(--drawer-indent-radius-active, var(--radius-lg)) 0 0;
      transform: translateY(
          calc(
            var(--drawer-indent-translate-y-active, var(--spacing-2)) *
              (1 - var(--drawer-swipe-progress, 0))
          )
        )
        scale(
          calc(
            var(--drawer-indent-scale-active, 0.97) +
              (1 - var(--drawer-indent-scale-active, 0.97)) * var(--drawer-swipe-progress, 0)
          )
        );
    }
  }

  @keyframes drawer-backdrop-in {
    from {
      opacity: 0;
      backdrop-filter: none;
    }
  }

  @keyframes drawer-backdrop-out {
    to {
      opacity: 0;
      backdrop-filter: none;
    }
  }

  @keyframes drawer-content-in-down {
    from {
      transform: translate3d(0, 100%, 0);
    }
  }

  @keyframes drawer-content-out-down {
    to {
      transform: translate3d(0, 100%, 0);
    }
  }

  @keyframes drawer-content-in-up {
    from {
      transform: translate3d(0, -100%, 0);
    }
  }

  @keyframes drawer-content-out-up {
    to {
      transform: translate3d(0, -100%, 0);
    }
  }

  @keyframes drawer-content-in-left {
    from {
      transform: translate3d(-100%, 0, 0);
    }
  }

  @keyframes drawer-content-out-left {
    to {
      transform: translate3d(-100%, 0, 0);
    }
  }

  @keyframes drawer-content-in-right {
    from {
      transform: translate3d(100%, 0, 0);
    }
  }

  @keyframes drawer-content-out-right {
    to {
      transform: translate3d(100%, 0, 0);
    }
  }
}
